#include <stdio.h>
#include <stdlib.h>
#include <ctype.h>

int main() {
	FILE *ulaz;
	char znak, ime[20];
	int broj_rijeci_velikim=0, razmak=1;

    printf("Unesite ime datoteke: ");
    scanf("%s", ime);

    ulaz = fopen(ime, "r");
    if (ulaz == NULL) {
        printf("Pogreska kod otvaranja datoteke %s!\n\n", ime);
        return 1;
    }

    while ((znak = fgetc(ulaz)) != EOF) {
        /* Ako je znak razmak, novi red ili tab, postavi razmak=1 */
        if (znak == ' ' || znak == '\n' || znak == '\t') {
            razmak = 1;
        } else {
            /* Ako prethodni znak je bio razmak, ovo je početak riječi */
            if (razmak == 1 && isupper((unsigned char)znak)) {
                ++broj_rijeci_velikim;
            }
            razmak = 0;
        }
    }

    printf("Broj riječi koje počinju velikim slovom: %d\n", broj_rijeci_velikim);

	fclose (ulaz);
	return 0;
}
